import{_ as t,o,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F11: 處分重大資產與資本配置","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F11_處分重大資產與資本配置_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F11_處分重大資產與資本配置_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/財務組/F11_處分重大資產與資本配置_投資研究員.md"};function l(s,n,a,g,c,d){return o(),r("div",null,[...n[0]||(n[0]=[e('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f11-處分重大資產與資本配置" tabindex="-1">F11: 處分重大資產與資本配置 <a class="header-anchor" href="#f11-處分重大資產與資本配置" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F11</li><li><strong>題目：</strong> 是否存在處分重大資產（如土地、專利、子公司）之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「資產效率分析 (Asset Efficiency)」與「資本配置策略 (Capital Allocation)」。能識別企業處分資產背後的真實動機——是「資產活化」以換取成長動能，還是「變賣家當」以美化短線財報，是鑑定獲利純度的核心把關者。</li><li><strong>意圖：</strong> 執行「非經常性損益與資本效率審計」，識別處分資產對獲利的實質影響，判定企業的「戰略轉向」或「財務健康度」，防止投資人被一次性業外獲利所誤導。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockFinancialStatements</code> 提取「其他利益及損失 (Other Gains and Losses)」與「處分資產利益 (Gain on Disposal of Property, Plant and Equipment)」。這是判定獲利純度的物理鐵證。</li><li><strong>【外部事實檢索：MOPS】</strong>：透過 Web Search 檢索「[公司名] 處分資產 公告」、「關閉廠區」、「資產活化」。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱「致股東報告書」與「財務報告附註」中關於處分損益的用途說明。</li></ol></li><li><strong>邏輯：</strong> 執行「獲利純度扣除分析」——計算排除處分利益後的實質營益率變動；執行「意圖判定算則」——分析資金是投入「再投資 (Reinvestment)」還是「償債/補坑 (Cash Survival)」。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>取數據</strong>：<code>python3 數據採集器.py cash_flow [股號]</code> → 抓 PropertyAndPlantAndEquipment 看處分</li><li><strong>取損益</strong>：<code>python3 數據採集器.py finance [股號]</code> → 抓 TotalNonoperatingIncomeAndExpense</li><li><strong>判讀</strong>：業外收支/稅前淨利 &gt;20% = 獲利結構脆弱，需深挖</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具提取「處分資產附註」</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①答詢詳解 ≥200 字、專家評析 ≥200 字；②空頭視角 ≥2 個</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【處分收益事実確認】</strong>：智慧體<strong>必須</strong>明確列出處分資產所貢獻的 EPS 數值。嚴禁在未扣除此項前給予「盈餘創新高」之結論。</li><li><strong>【業務動能交叉審核】</strong>：若處分項目為「主要生產設備」或「研發大樓」，必須將其定義為「業務萎縮風險」。</li><li><strong>【資本配置穿透】</strong>：智慧體必須追蹤資金去向。若資金用於「發放現金股利」而非「降低負債」或「擴產」，必須判定為「祖產派現」之治理負面訊號。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：絕對禁用「獲利亮眼」、「表現不俗」。必須量化為具體的「業外佔淨利比 %」與「本業實質營利率階差 (In-house Margin Spread)」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f11-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F11 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f11-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F11 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「處分屬性+獲利純度」結構（例：獲利 X% 來自處分 A 資產，屬 [業務轉骨/救急補坑]，扣非後本業營利率 [改善/惡化]，獲利質量判定為 [低劣/純淨]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：主動處分低效益之非核心資產，所得資金明確投入具成長性之研發或產能擴展，資產週轉率顯著提升。</li><li><strong>A (良)</strong>：常態性資產活化或設備汰換，處分損益佔淨利比低於 15%，無礙本業競爭力。</li><li><strong>B (持平)</strong>：處分核心資產（專利、總部、關鍵設備）以維持帳面獲利，顯示本業現金流斷裂或面臨財務危機，獲利純度極低。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：依照以下三個維度回答： <ol><li><strong>獲利含金量穿透 (Earnings Purity)</strong>：明確列出業外損益佔比，並還原本業實質數據。</li><li><strong>戰略意圖判別 (Strategic Intent)</strong>：根據資金流向診斷該公司是處於「擴張策略」還是「生存防禦」。</li><li><strong>資產結構變動 (Asset Efficiency)</strong>：分析處分後對整體 ROA/ROE 與資產週轉率的長期影響。</li></ol></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>financial</code> 損益表業外科目名稱與 MOPS 公告 ID。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注處分行為是否發生在「季底」或「財務緊縮期」。若公司頻繁透過變賣資產湊數以達成年度財測，專家應在此處診斷其具備「資本配置盲目」與「治理透明度低」之雙重風險。</li></ul>',12)])])}const f=t(i,[["render",l]]);export{h as __pageData,f as default};
